async (page) => {
  const result = await page.evaluate((id) => window.__talkToNPC(id), '1-19601828');
  await page.waitForTimeout(2000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({result, dialogue: parsed.ui_state.npc_dialogue, quest_panel: parsed.ui_state.quest_panel_visible, pos: parsed.player_position});
}

async (page) => {
  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? (m.ascii + '\n\n' + m.legendText) : 'No map';
  });
  return asciiMap;
}

